using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the discriminator property from "Discriminator" to "$type".
            // Preserve "Discriminator" for compatibility with existing 500K documents
            // and direct SQL queries that reference c.Discriminator.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed the id format from "EntityType|Key" to just "Key".
            // Preserve the "Product|{Id}" format so existing documents remain readable.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id")
                .HasValueGenerator<ProductIdValueGenerator>();
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // EF Core 9 removed sync query support for Cosmos.
        // This is handled by converting all call sites to async (see CosmosQuery.cs).
    }
}

// EF Core 9 no longer generates "EntityType|Key" id values by default.
// This generator preserves the legacy format for backward compatibility.
class ProductIdValueGenerator : Microsoft.EntityFrameworkCore.ValueGeneration.ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(Microsoft.EntityFrameworkCore.ChangeTracking.EntityEntry entry)
    {
        var id = entry.Property("Id").CurrentValue;
        return $"Product|{id}";
    }
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

