using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1: EF Core 9 renamed the discriminator property
            // from "Discriminator" to "$type". Existing documents and direct SQL
            // queries (e.g. WHERE c.Discriminator = 'Product') would break.
            // Fix: explicitly preserve the old property name.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2: EF Core 9 changed the Cosmos id format from
            // "EntityType|Key" (e.g. "Product|123") to just the key value ("123").
            // Existing 500K documents use the old format and would become unreadable.
            // Fix: override the id shadow property's value generator.
            entity.Property<string>("__id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3: HasIndex() now throws for the Cosmos provider
            // instead of being silently ignored. The original HasIndex(p => p.Sku)
            // has been removed. Use Cosmos indexing policy on the container instead.
        });
    }
}

/// <summary>
/// Generates Cosmos id values in the legacy EF Core 8 format: "Product|{key}".
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
    {
        var key = entry.Property("Id").CurrentValue;
        return $"Product|{key}";
    }
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

